"use strict";(self.webpackChunksuprema_docs=self.webpackChunksuprema_docs||[]).push([["69079"],{15870(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"2026-06-changelog","metadata":{"permalink":"/docs/changelog/2026-06-changelog","source":"@site/changelog/2026-06-changelog.md","title":"2026\uB144 6\uC6D4","description":"2026\uB144 6\uC6D4 Suprema Docs \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","date":"2026-07-01T12:00:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"2026\uB144 6\uC6D4","description":"2026\uB144 6\uC6D4 Suprema Docs \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","slug":"2026-06-changelog","date":"2026-07-01T12:00","isTranslationMissing":false},"unlisted":false,"nextItem":{"title":"2026\uB144 5\uC6D4","permalink":"/docs/changelog/2026-05-changelog"}},"content":"\uC774\uBC88 6\uC6D4, **Suprema Docs**\uC5D0 \uAD75\uC9C1\uD55C \uC18C\uC2DD\uC774 \uAC00\uB4DD\uD569\uB2C8\uB2E4. \uC288\uD504\uB9AC\uB9C8\uC758 **AI Camera ViOnyx**\uAC00 \uC0C8\uB86D\uAC8C \uCD9C\uC2DC\uB418\uC5B4 \uC124\uCE58 \uB9E4\uB274\uC5BC\uACFC \uC6F9 \uC11C\uBC84 \uB9E4\uB274\uC5BC\uC744 \uD568\uAED8 \uACF5\uAC1C\uD588\uC2B5\uB2C8\uB2E4. \uB354\uBD88\uC5B4 \uC2A4\uB9C8\uD2B8\uD3F0\uC5D0\uC11C \uCD9C\uC785 \uD1B5\uC81C \uC2DC\uC2A4\uD15C\uC744 \uAD00\uB9AC\uD560 \uC218 \uC788\uB294 **BioStar X \uBAA8\uBC14\uC77C** \uB9E4\uB274\uC5BC\uACFC \uC2DC\uC2A4\uD15C \uBCF4\uC548 \uC218\uC900\uC744 \uB192\uC774\uAE30 \uC704\uD55C **BioStar X \uBCF4\uC548 \uAC15\uD654 \uAC00\uC774\uB4DC**\uB3C4 \uC0C8\uB86D\uAC8C \uAC8C\uC2DC\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC9C0\uAE08 \uBC14\uB85C \uD655\uC778\uD574\uBCF4\uC138\uC694.\\n\\n![Suprema Docs 26.06 Changelogs](/img/changelogs/changelogs-202606.png)\\n\\n{/* truncate */}\\n\\n## Document Hub \uC624\uD508\\n\\n![](/img/changelogs/document_hub_banner.png)\\n\\n\uC288\uD504\uB9AC\uB9C8 \uC81C\uD488\uC758 \uB9E4\uB274\uC5BC, \uB9B4\uB9AC\uC2A4 \uB178\uD2B8, \uB4DC\uB9B4\uB9C1 \uD15C\uD50C\uB9BF, A&E \uC0AC\uC591\uC11C\uB97C \uD55C\uACF3\uC5D0\uC11C \uB2E4\uC6B4\uB85C\uB4DC\uD560 \uC218 \uC788\uB294 [**Document Hub**](../dochub)\uB97C \uC624\uD508\uD588\uC2B5\uB2C8\uB2E4.\\n\\n## AI \uCE74\uBA54\uB77C\\n\\n\uC288\uD504\uB9AC\uB9C8\uC758 \uC0C8\uB85C\uC6B4 \uC601\uC0C1\uBCF4\uC548 \uC81C\uD488, AI \uCE74\uBA54\uB77C ViOnyx\uC758 \uB9E4\uB274\uC5BC\uC744 \uCD94\uAC00\uD588\uC2B5\uB2C8\uB2E4.\\n\\n* [ViOnyx \uC124\uCE58 \uB9E4\uB274\uC5BC](../device/vionyx/)\\n\\n* [ViOnyx \uC6F9 \uC11C\uBC84 \uB9E4\uB274\uC5BC](../device/vionyx_webserver/)\\n\\n## \uD50C\uB7AB\uD3FC\\n\\n### BioStar X\\n\\n* [1.0.2 \uD56B\uD53D\uC2A4 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8](../platform/biostar_x/release-notes/102) \uC0B4\uD3B4\uBCF4\uAE30\\n\\n* [BioStar X \uC5C5\uADF8\uB808\uC774\uB4DC\uD558\uAE30](../platform/biostar_x/migration-x): \uC5C5\uADF8\uB808\uC774\uB4DC \uC2DC \uCD5C\uC18C \uC0AC\uC591 \uC548\uB0B4 \uBB38\uAD6C \uCD94\uAC00\\n\\n* [BioStar X API](../developer/bsxapi) \uBB38\uC11C \uB9AC\uB274\uC5BC\\n\\n### BioStar X Mobile\\n\\n[BioStar X Mobile](../platform/biostar_x_mobile) \uC571 \uC0AC\uC6A9\uC790 \uB9E4\uB274\uC5BC\uC744 \uC0C8\uB86D\uAC8C \uCD94\uAC00\uD588\uC2B5\uB2C8\uB2E4. \uBAA8\uBC14\uC77C \uAE30\uAE30\uC5D0\uC11C \uC0AC\uC6A9\uC790 \uB4F1\uB85D, \uCD9C\uC785\uBB38 \uC6D0\uACA9 \uC81C\uC5B4, \uC2E4\uC2DC\uAC04 \uC774\uBCA4\uD2B8 \uBAA8\uB2C8\uD130\uB9C1, \uACBD\uBCF4 \uCC98\uB9AC \uB4F1\uC758 \uAE30\uB2A5\uC744 \uC548\uB0B4\uD569\uB2C8\uB2E4.\\n\\n### BioStar Air\\n\\n\uD06C\uB9AC\uB374\uC15C \uC7AC\uBC1C\uAE09\uACFC \uAD00\uB828\uD55C \uC548\uB0B4 \uBB38\uAD6C \uCD94\uAC00\\n\\n* [\uC0AC\uC6A9\uC790 \uAD00\uB9AC\uD558\uAE30](../platform/biostar_air/user-management-user-list#manageUserStatus)\\n\\n* [\uBAA8\uBC14\uC77C \uCE74\uB4DC \uBB38\uC81C \uD574\uACB0](../platform/biostar_air/troubleshooting-suprema-pass-app#mobileCardDeleted)\\n\\n## \uC7A5\uCE58\\n\\n### \uC7A5\uCE58 \uC5C5\uB370\uC774\uD2B8\\n\\n* [BioStation 3 Max](../device/biostation_3_max/)\\n  \\n  * [\uB9C8\uC2A4\uD130 \uAD00\uB9AC\uC790](../device/biostation_3_max/getting-started) \uAD00\uB828 \uB0B4\uC6A9 \uC5C5\uB370\uC774\uD2B8\\n  \\n  * [\uC81C\uD488 \uC0AC\uC591](../device/biostation_3_max/product-specifications) \uC5C5\uB370\uC774\uD2B8\\n  \\n* [BioStation 3](../device/biostation_3/)\\n  \\n  * [\uBCBD\uAC78\uC774\uC6A9 \uBE0C\uB798\uD0B7 \uC774\uBBF8\uC9C0](../device/biostation_3/getting-started) \uBCC0\uACBD\\n\\n  * [\uB9C8\uC2A4\uD130 \uAD00\uB9AC\uC790](../device/biostation_3/getting-started) \uAD00\uB828 \uB0B4\uC6A9 \uC5C5\uB370\uC774\uD2B8\\n  \\n  * [\uD2F8\uD305 \uBE0C\uB798\uD0B7 \uC124\uCE58](../device/biostation_3/installation) \uC548\uB0B4 \uCD94\uAC00\\n  \\n  * [\uC81C\uD488 \uC0AC\uC591](../device/biostation_3/product-specifications) \uC5C5\uB370\uC774\uD2B8\\n\\n* [X-Station 2](../device/xstation_2/)\\n\\n  * [\uB9C8\uC2A4\uD130 \uAD00\uB9AC\uC790](../device/xstation_2/getting-started) \uAD00\uB828 \uB0B4\uC6A9 \uC5C5\uB370\uC774\uD2B8\\n  \\n  * [Camera QR \uC9C0\uC6D0](../device/xstation_2/authentication) \uAD00\uB828 \uB0B4\uC6A9 \uC5C5\uB370\uC774\uD2B8\\n  \\n  * [\uC81C\uD488 \uC0AC\uC591](../device/xstation_2/product-specifications) \uC5C5\uB370\uC774\uD2B8\\n  \\n* [BioStation 2a](../device/biostation_2a/)\\n  \\n  * [\uB9C8\uC2A4\uD130 \uAD00\uB9AC\uC790](../device/biostation_2a/getting-started) \uAD00\uB828 \uB0B4\uC6A9 \uC5C5\uB370\uC774\uD2B8\\n  \\n  * [\uC81C\uD488 \uC0AC\uC591](../device/biostation_2a/product-specifications) \uC5C5\uB370\uC774\uD2B8\\n\\n* [BioLite N2](../device/biolite_n2/)\\n\\n  * [\uB9C8\uC2A4\uD130 \uAD00\uB9AC\uC790](../device/biolite_n2/getting-started) \uAD00\uB828 \uB0B4\uC6A9 \uC5C5\uB370\uC774\uD2B8\\n  \\n  * [\uC81C\uD488 \uC0AC\uC591](../device/biolite_n2/product-specifications) \uC5C5\uB370\uC774\uD2B8\\n\\n* \uC81C\uD488 \uC0AC\uC591 \uC5C5\uB370\uC774\uD2B8\\n\\n  * [XPass 2](../device/xpass_2/product-specifications)\\n\\n  * [XPass D2](../device/xpass_d2/product-specifications)\\n\\n  * [BioEntry W3](../device/bioentry_w3/product-specifications)\\n\\n### \uB9B4\uB9AC\uC2A4 \uB178\uD2B8\\n\\n* [Door Interface](../device/doorinterface/release-notes/103): 1.0.3 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [ViOnyx](../device/vionyx/release-notes/101): 1.0.1 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [BioEntry W3](../device/bioentry_w3/release-notes/103): 1.0.3 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n## \uC81C\uD488 \uD65C\uC6A9 \uAC00\uC774\uB4DC\\n\\n### \uB9C8\uC2A4\uD130 \uAD00\uB9AC\uC790\\n\\n[\uB9C8\uC2A4\uD130 \uAD00\uB9AC\uC790 \uC124\uC815\uD558\uAE30](../how-to/master-admin): \uB9C8\uC2A4\uD130 \uAD00\uB9AC\uC790 \uB0B4\uC6A9 \uC804\uBC18 \uAC1C\uC815 \uBC0F CE\uD5A5 \uC81C\uD488 \uBC30\uCE58 \uC815\uBCF4 \uCD94\uAC00\\n\\n### BioStar X \uBCF4\uC548 \uAC15\uD654\\n\\n[BioStar X \uBCF4\uC548 \uAC15\uD654 \uAC00\uC774\uB4DC](../how-to/bsx_hardening/)\uB97C \uC0C8\uB86D\uAC8C \uACF5\uAC1C\uD569\uB2C8\uB2E4. \uCD9C\uC785 \uD1B5\uC81C \uC2DC\uC2A4\uD15C\uC758 \uBCF4\uC548 \uC218\uC900\uC744 \uB192\uC774\uAE30 \uC704\uD55C \uC11C\uBC84 \uAC15\uD654, \uB124\uD2B8\uC6CC\uD06C \uBC29\uD654\uBCBD, \uD328\uCE58 \uAD00\uB9AC \uB4F1 \uC2E4\uC9C8\uC801\uC778 \uAD8C\uACE0 \uC0AC\uD56D\uC744 \uB2E8\uACC4\uC801\uC73C\uB85C \uC548\uB0B4\uD569\uB2C8\uB2E4.\\n\\n## \uC778\uD14C\uADF8\uB808\uC774\uC158\\n\\n[Genetec](../integration/genetec/): \uC2DC\uC2A4\uD15C \uAD00\uB9AC \uAD00\uB828 \uB0B4\uC6A9 \uC5C5\uB370\uC774\uD2B8"},{"id":"2026-05-changelog","metadata":{"permalink":"/docs/changelog/2026-05-changelog","source":"@site/changelog/2026-05-changelog.md","title":"2026\uB144 5\uC6D4","description":"2026\uB144 5\uC6D4 Suprema Docs \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","date":"2026-05-28T12:00:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"2026\uB144 5\uC6D4","description":"2026\uB144 5\uC6D4 Suprema Docs \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","slug":"2026-05-changelog","date":"2026-05-28T12:00","isTranslationMissing":false},"unlisted":false,"prevItem":{"title":"2026\uB144 6\uC6D4","permalink":"/docs/changelog/2026-06-changelog"},"nextItem":{"title":"2026\uB144 4\uC6D4","permalink":"/docs/changelog/2026-04-changelog"}},"content":"\uC774\uBC88 5\uC6D4, **Suprema Docs**\uB294 \uB354 \uD06C\uAC8C, \uB354 \uB113\uAC8C \uC6C0\uC9C1\uC600\uC2B5\uB2C8\uB2E4. \uC2E0\uADDC \uC7A5\uCE58 **BioStation 3 Max**\uAC00 \uC0C8\uB86D\uAC8C \uB77C\uC778\uC5C5\uC5D0 \uD569\uB958\uD588\uC2B5\uB2C8\uB2E4. BioStar X\uC640 BioStar Air\uC758 \uAE30\uB2A5\uB3C4 \uD55C\uCE35 \uBCF4\uAC15\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uD2B9\uD788 \uC774\uBC88 \uB2EC\uC5D4 \uD0C0\uC0AC \uC81C\uD488\uACFC\uC758 \uC5F0\uB3D9\uC744 \uB2E4\uB8E8\uB294 **\uC778\uD14C\uADF8\uB808\uC774\uC158** \uCE74\uD14C\uACE0\uB9AC\uAC00 \uC0C8\uB86D\uAC8C \uBB38\uC744 \uC5F4\uC5C8\uC73C\uB2C8, \uB354\uC6B1 \uD48D\uC131\uD574\uC9C4 Suprema Docs\uB97C \uC9C0\uAE08 \uBC14\uB85C \uB9CC\uB098\uBCF4\uC138\uC694.\\n\\n![Suprema Docs 26.05 Changelogs](/img/changelogs/changelogs-202605.png)\\n\\n{/* truncate */}\\n\\n## Platform\\n\\n### BioStar X\\n\\n* [1.0.2 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8](../platform/biostar_x/release-notes/102) \uC0B4\uD3B4\uBCF4\uAE30\\n\\n* [\uBA54\uC778 \uC11C\uBC84\uC758 IP \uC8FC\uC18C \uBCC0\uACBD\uD558\uAE30](../platform/biostar_x/change-ip): BioStar X \uBA54\uC778 \uC11C\uBC84\uC758 IP \uC8FC\uC18C \uBCC0\uACBD \uC548\uB0B4 \uCD94\uAC00\\n\\n* [\uB514\uB809\uD1A0\uB9AC \uC5F0\uB3D9 \uC124\uC815\uD558\uAE30](../platform/biostar_x/settings-diretory-integration): \uB514\uB809\uD1A0\uB9AC \uC11C\uBE44\uC2A4 \uC5F0\uB3D9 \uC124\uC815\uC5D0 **\uCD94\uAC00/\uC5C5\uB370\uC774\uD2B8/\uC0AD\uC81C** \uBAA8\uB4DC \uCD94\uAC00\\n\\n* [\uC2DC\uC2A4\uD15C \uBCF5\uC6D0\uD558\uAE30](../platform/biostar_x/settings-system-system-restore): \uBCF5\uC6D0 \uB3C4\uAD6C \uC0AC\uC6A9\uC5D0 \uB300\uD55C \uC0C1\uC138 \uACFC\uC815 \uC5C5\uB370\uC774\uD2B8\\n\\n* [\uC7A5\uCE58 \uB0B4 \uC774\uBCA4\uD2B8 \uB85C\uADF8 \uC0AD\uC81C](../platform/biostar_x/settings-device-using-functions#deleteLogsFromDevice): \uC7A5\uCE58\uC5D0 \uC800\uC7A5\uB41C \uC774\uBCA4\uD2B8 \uB85C\uADF8 \uC0AD\uC81C \uAE30\uB2A5 \uCD94\uAC00\\n\\n* [VMS \uC5F0\uB3D9\uD558\uAE30](../platform/biostar_x/settings-video-integration): **Nx Witness v6.x.x**\uC5D0 \uB300\uD55C \uC9C0\uC6D0 \uCD94\uAC00\\n\\n* [\uCE74\uBA54\uB77C \uC124\uC815\uD558\uAE30](../platform/biostar_x/settings-videos-camera#addCameraPermission): \uCE74\uBA54\uB77C \uADF8\uB8F9 \uAD8C\uD55C \uC124\uC815\uC5D0 \uB300\uD55C \uC548\uB0B4 \uCD94\uAC00\\n\\n* BioStation 3 Max, XPass Q2 \uC7A5\uCE58\uC5D0 \uB300\uD55C \uC9C0\uC6D0 \uC0AC\uC591 \uCD94\uAC00\\n\\n### BioStar Air\\n\\n* [SW 2.12 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8](../platform/biostar_air/release-notes/bsair-release-notes#2120) \uC0B4\uD3B4\uBCF4\uAE30\\n\\n* [\uC5D0\uC5B4\uD31D \uD328\uCE58 \uC124\uCE58](../platform/biostar_air/install-airfob-patch): \uC5D0\uC5B4\uD31D \uD328\uCE58 \uC124\uCE58 \uC548\uB0B4 \uCD94\uAC00\\n\\n---\\n\\n## Devices\\n\\n### \uC2E0\uADDC \uC7A5\uCE58\\n\\n\uC288\uD504\uB9AC\uB9C8 \uD50C\uB798\uADF8\uC2ED AI \uAE30\uBC18 \uBC14\uC774\uC624\uC778\uC2DD \uC81C\uD488 BioStation 3 Max\uC758 \uB9E4\uB274\uC5BC\uC744 \uC624\uD508\uD588\uC2B5\uB2C8\uB2E4.\\n\\n* [BioStation 3 Max](../device/biostation_3_max)\\n\\n### \uC7A5\uCE58 \uC5C5\uB370\uC774\uD2B8\\n\\n* [BioEntry W3](../device/bioentry_w3/) 1.0.2 \uBC84\uC804 \uC5C5\uB370\uC774\uD2B8 \uC801\uC6A9\\n\\n  * \uBCBD\uAC78\uC774\uC6A9 \uBE0C\uB798\uD0B7 \uC774\uBBF8\uC9C0 \uBCC0\uACBD\\n\\n  * [RS-485 \uC0AC\uC6A9 \uAD00\uB828 \uC8FC\uC758 \uC0AC\uD56D](../device/bioentry_w3/getting-started#cable) \uCD94\uAC00\\n\\n* [Device Manager](../device/device_manager/) 1.2.3 \uBC84\uC804 \uC5C5\uB370\uC774\uD2B8 \uC801\uC6A9\\n\\n  * [XPass D2 \uC124\uC815\uD558\uAE30](../device/device_manager/xpd2-settings): **EV2/EV3 \uBCF4\uC548 \uBA54\uC2DC\uC9D5 \uAC15\uC81C** \uAE30\uB2A5 \uCD94\uAC00\\n\\n### \uC7A5\uCE58 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8\\n\\n* [BioEntry R2](../device/bioentry_r2/release-notes/142): 1.4.2 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [CoreStation](../device/corestation_40/release-notes/172): 1.7.2 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [CoreStation 20](../device/corestation_20/release-notes/104): 1.0.4 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [BioEntry W3](../device/bioentry_w3/release-notes/102): 1.0.2 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [Device Manager](../device/device_manager/release-notes/123): 1.2.3 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [FaceStation F2](../device/facestation_f2/release-notes/222): 2.2.2 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n---\\n\\n## \uC778\uD14C\uADF8\uB808\uC774\uC158\\n\\n**\uC778\uD14C\uADF8\uB808\uC774\uC158(Integration)** \uCE74\uD14C\uACE0\uB9AC\uB97C \uCD94\uAC00\uD588\uC2B5\uB2C8\uB2E4. \uD0C0\uC0AC \uC81C\uD488\uACFC \uC288\uD504\uB9AC\uB9C8 \uC7A5\uCE58\uB97C \uC5F0\uB3D9\uD558\uB294 \uBC29\uBC95\uC744 \uD655\uC778\uD574\uBCF4\uC138\uC694.\\n\\n* [Genetec](../integration/genetec/)\\n\\n* [Gallagher](../integration/gallagher/)\\n\\n* [Software House](../integration/ccure/)"},{"id":"2026-04-changelog","metadata":{"permalink":"/docs/changelog/2026-04-changelog","source":"@site/changelog/2026-04-changelog.md","title":"2026\uB144 4\uC6D4","description":"2026\uB144 4\uC6D4 Suprema Docs \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","date":"2026-05-01T12:00:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"2026\uB144 4\uC6D4","description":"2026\uB144 4\uC6D4 Suprema Docs \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","slug":"2026-04-changelog","date":"2026-05-01T12:00","isTranslationMissing":false},"unlisted":false,"prevItem":{"title":"2026\uB144 5\uC6D4","permalink":"/docs/changelog/2026-05-changelog"},"nextItem":{"title":"2026\uB144 3\uC6D4","permalink":"/docs/changelog/2026-03-changelog"}},"content":"4\uC6D4\uC740 **Suprema Docs**\uC5D0\uAC8C \uB9E4\uC6B0 \uBC14\uC05C \uD55C\uB2EC\uC774\uC5C8\uC2B5\uB2C8\uB2E4. \uD50C\uB7AB\uD3FC\uBD80\uD130 \uC7A5\uCE58, \uAC1C\uBC1C\uC790 API\uAE4C\uC9C0 \uC0C8\uB85C\uC6B4 \uC5C5\uB370\uC774\uD2B8\uB4E4\uC774 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uBC88 \uB2EC \uC5B4\uB5A4 \uBCC0\uD654\uAC00 \uC788\uC5C8\uB294\uC9C0 \uD568\uAED8 \uC0B4\uD3B4\uBCF4\uC138\uC694.\\n\\n![Suprema Docs 26.04 Changelogs](/img/changelogs-202604.png)\\n\\n{/* truncate */}\\n\\n## Platform\\n\\n### BioStar X\\n\\n* [VMS \uC5F0\uB3D9\uD558\uAE30](../platform/biostar_x/settings-video-integration#install-vms-certification): \uC778\uC99D\uC11C \uC124\uCE58 \uACBD\uB85C \uC608\uC2DC \uCD94\uAC00\\n\\n* [\uC11C\uBC84 \uC0C1\uC138 \uC124\uC815\uD558\uAE30](../platform/biostar_x/settings-server-server#custom-field): \uCEE4\uC2A4\uD140 \uC0AC\uC6A9\uC790 \uD544\uB4DC\uB97C \uD30C\uC77C \uC5C5\uB85C\uB4DC \uC635\uC158\uC73C\uB85C \uC9C0\uC815\uD560 \uB54C \uD30C\uC77C \uD615\uC2DD\uC5D0 \uB300\uD55C \uC81C\uD55C \uC5C6\uC74C\uC744 \uB178\uD2B8 \uBB38\uAD6C \uCD94\uAC00\\n\\n* [\uBE44\uB514\uC624 \uB77C\uC774\uC120\uC2A4](../platform/biostar_x/licensing#features-add-ons) \uAD00\uB828 \uC124\uBA85 \uC5C5\uB370\uC774\uD2B8\\n\\n### BioStar Air\\n\\n* BioStar Air [\uD38C\uC6E8\uC5B4 2.12 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8](../platform/biostar_air/release-notes/firmware) \uC5C5\uB370\uC774\uD2B8\\n\\n* BioStar Air \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uBB38\uC11C \uAD6C\uC870 \uAC1C\uD3B8\\n\\n  * [\uC18C\uD504\uD2B8\uC6E8\uC5B4 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8](../platform/biostar_air/release-notes/software)\\n\\n  * [\uD38C\uC6E8\uC5B4 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8](../platform/biostar_air/release-notes/firmware)\\n\\n## Devices\\n\\n\uC2E0\uADDC \uB9B4\uB9AC\uC2A4 \uB178\uD2B8\uB97C \uCD94\uAC00\uD558\uACE0 \uC0C8\uB85C\uC6B4 \uC7A5\uCE58 \uBB38\uC11C\uB97C \uC5C5\uB370\uC774\uD2B8\uD588\uC2B5\uB2C8\uB2E4.\\n\\n* [XPass Q2 \uC124\uCE58 \uAC00\uC774\uB4DC](../device/xpass_q2) \uC2E0\uADDC \uC81C\uC791\\n\\n* [XPass D2](../device/xpass_d2/release-notes/183): 1.8.3 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [BioStation 2a](../device/biostation_2a/release-notes/121): 1.2.1 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [X-Station 2](../device/xstation_2/release-notes/141): 1.4.1 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [BioLite N2](../device/biolite_n2/release-notes/171): 1.7.1 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [BioStation 3](../device/biostation_3/release-notes/143): 1.4.3 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [XPass 2](../device/xpass_2/release-notes/152): 1.5.2 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n## Developer\\n\\n* API \uBB38\uC11C \uC5C5\uB370\uC774\uD2B8: [Export as CSV API](../developer/bsxapi?api=export-as-csv)"},{"id":"2026-03-changelog","metadata":{"permalink":"/docs/changelog/2026-03-changelog","source":"@site/changelog/2026-03-changelog.md","title":"2026\uB144 3\uC6D4","description":"Suprema Docs\uC758 2\uC6D4\uBD80\uD130 3\uC6D4\uAE4C\uC9C0\uC758 \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","date":"2026-04-08T12:00:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"2026\uB144 3\uC6D4","description":"Suprema Docs\uC758 2\uC6D4\uBD80\uD130 3\uC6D4\uAE4C\uC9C0\uC758 \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","slug":"2026-03-changelog","date":"2026-04-08T12:00","isTranslationMissing":false},"unlisted":false,"prevItem":{"title":"2026\uB144 4\uC6D4","permalink":"/docs/changelog/2026-04-changelog"},"nextItem":{"title":"2026\uB144 1\uC6D4","permalink":"/docs/changelog/2026-01-02-changelog"}},"content":"\uC774\uBC88 3\uC6D4 \uC5C5\uB370\uC774\uD2B8\uB294 \uB354\uC6B1 \uC9C1\uAD00\uC801\uC778 \uC778\uD130\uD398\uC774\uC2A4\uC640 \uAC15\uD654\uB41C \uAC80\uC0C9 \uAE30\uB2A5\uC73C\uB85C **Suprema Docs** \uC0AC\uC6A9 \uACBD\uD5D8\uC744 \uAC1C\uC120\uD588\uC2B5\uB2C8\uB2E4. \uB3D9\uC2DC\uC5D0 **BioStar Air** \uAD00\uB9AC\uC790 \uAC00\uC774\uB4DC\uB97C \uC644\uC804\uD788 \uC7AC\uAD6C\uC131\uD558\uC5EC \uC0AC\uC6A9\uC790 \uAD00\uB9AC\uBD80\uD130 \uCD9C\uC785 \uD1B5\uC81C, \uBE44\uB514\uC624 \uAC10\uC2DC\uAE4C\uC9C0 \uBAA8\uB4E0 \uAE30\uB2A5\uC744 \uD55C\uB208\uC5D0 \uD30C\uC545\uD560 \uC218 \uC788\uB3C4\uB85D \uC815\uB9AC\uD588\uC2B5\uB2C8\uB2E4.\\n\\n![Suprema Docs 26.03 Changelogs](/img/changelogs-202603.png)\\n\\n{/* truncate */}\\n\\n## Docs\\n\\n* \uCCAB \uD398\uC774\uC9C0 \uB514\uC790\uC778 \uBCC0\uACBD\\n\\n  ![Suprema Docs home](/img/changelogs/changelog-03-home.png)\\n\\n* \uAC80\uC0C9 \uAE30\uB2A5 \uAC15\uD654\\n\\n  \uC81C\uD488\uBCC4 \uAC80\uC0C9 \uAE30\uB2A5 \uCD94\uAC00, \uB2E8\uCD95\uD0A4(ctrl + k)\uB85C \uAC80\uC0C9 \uCC3D \uD638\uCD9C\\n\\n  ![Suprema Docs home](/img/changelogs/changelog-03-search.png)\\n\\n## Platform\\n\\n### BioStar X\\n\\n* [VMS \uC11C\uBC84 \uC5F0\uB3D9 \uC2DC \uC778\uC99D\uC11C \uC124\uCE58 \uAD00\uB828 \uBB38\uC11C](../platform/biostar_x/settings-video-integration) \uC5C5\uB370\uC774\uD2B8\\n\\n### BioStar Air\\n\\n* [BioStar Air \uAC00\uC774\uB4DC](../platform/biostar_air/) \uBB38\uC11C \uC804\uCCB4 \uC7AC\uAD6C\uC131 \uBC0F \uCD5C\uC801\uD654 \uC644\uB8CC\\n\\n* BioStar Air \uB2E4\uAD6D\uC5B4 \uC9C0\uC6D0 \uD655\uB300: \uC601\uBB38, \uC77C\uBCF8\uC5B4, \uC2A4\uD398\uC778\uC5B4 \uBC88\uC5ED \uCD94\uAC00\\n\\n  * \uC0AC\uC6A9\uC790 \uAD00\uB9AC, \uCD9C\uC785 \uAD8C\uD55C \uAD00\uB9AC, \uBE44\uB514\uC624 \uAD00\uB9AC \uB4F1 \uC8FC\uC694 \uAE30\uB2A5 \uBB38\uC11C \uCD94\uAC00\\n\\n  * \uC601\uBB38 \uC774\uBBF8\uC9C0 \uBC0F \uC0AC\uC6A9\uC790 \uC778\uD130\uD398\uC774\uC2A4 \uC2A4\uD06C\uB9B0\uC0F7 \uCD94\uAC00\\n\\n* BioStar Air \uBAA9\uCC28 \uAD6C\uC870 \uAC1C\uC120 \uBC0F \uC139\uC158 \uC7AC\uC870\uC815\\n\\n## Devices\\n\\n\uC2E0\uADDC \uB9B4\uB9AC\uC2A4 \uB178\uD2B8\uB97C \uCD94\uAC00\uD558\uACE0 \uAE30\uC874 \uC7A5\uCE58 \uBB38\uC11C\uB97C \uC5C5\uB370\uC774\uD2B8\uD588\uC2B5\uB2C8\uB2E4.\\n\\n### \uC7A5\uCE58 \uBB38\uC11C \uC5C5\uB370\uC774\uD2B8\\n\\n* [XPass 2](../device/xpass_2/release-notes/151): 1.5.1 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n\x3c!-- * [BioEntry W3](../device/biostation_3_max/): 1.0.2 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00 --\x3e\\n\\n* [Device Manager](../device/device_manager/release-notes/122): \uC571 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCE74\uD14C\uACE0\uB9AC \uC2E0\uC124 \uBC0F 1.2.2 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* [BioEntry P2](../device/bioentry_p2/release-notes/160): 1.6.0 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n* \uC7A5\uCE58 \uACF5\uC7A5 \uCD08\uAE30\uD654 \uBC84\uD2BC \uC704\uCE58 \uC548\uB0B4 \uC774\uBBF8\uC9C0 \uCD94\uAC00\\n\\n## Developer\\n\\n* API \uBB38\uC11C \uC5C5\uB370\uC774\uD2B8: [Create BioStar X QR](../developer/bsxapi?api=create-biostar-x-qr)\\n\\n* Device SDK: 2.9.12 \uBC84\uC804 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8 \uCD94\uAC00\\n\\n## \uB2E4\uAD6D\uC5B4 \uC9C0\uC6D0\\n\\n* \uC77C\uBCF8\uC5B4, \uC2A4\uD398\uC778\uC5B4 \uBB38\uC11C\uC758 \uC644\uC131\uB3C4 \uD5A5\uC0C1\\n\\n  * \uBB38\uC11C \uC81C\uBAA9 \uBC0F \uB0B4\uC6A9 \uC77C\uAD00\uC131 \uAC1C\uC120\\n\\n  * \uC624\uBC88\uC5ED \uC218\uC815 \uBC0F \uC6A9\uC5B4 \uD1B5\uC77C\\n\\n  * \uB744\uC5B4\uC4F0\uAE30 \uBC0F \uBB38\uBC95 \uC218\uC815\\n\\n* \uC601\uBB38 \uBC88\uC5ED \uB300\uD3ED \uC5C5\uB370\uC774\uD2B8\\n\\n  * \uAE30\uC220 \uC6A9\uC5B4 \uD45C\uC900\uD654\\n\\n  * \uBB38\uC7A5 \uAD6C\uC870 \uBC0F \uD45C\uD604 \uAC1C\uC120\\n\\n## \uC624\uD508 \uC18C\uC2A4 \uB77C\uC774\uC120\uC2A4\\n\\n* \uB77C\uC774\uC120\uC2A4 \uACE0\uC9C0\uBB38 \uCD94\uAC00: [BSD-2-Clause](../legal/open-source-licenses#the-2-clause-bsd-license), [BSD-3-Clause](../legal/open-source-licenses#the-3-clause-bsd-license), [EPL](../legal/open-source-licenses#eclipse-public-license), [EDL](../legal/open-source-licenses#eclipse-distribution-license), [LGPLv2.1](../legal/open-source-licenses#gnu-lesser-general-public-v21-license)\u200B, [GPLv2](../legal/open-source-licenses#gnu-general-public-v2-license)\u200B, [ISC](../legal/open-source-licenses#isc-license), [zlib](../legal/open-source-licenses#zlib-license)"},{"id":"2026-01-02-changelog","metadata":{"permalink":"/docs/changelog/2026-01-02-changelog","source":"@site/changelog/2026-01-02-changelog.md","title":"2026\uB144 1\uC6D4","description":"Suprema Docs\uB97C \uCC98\uC74C \uBC30\uD3EC\uD55C \uD6C4 \uC9C0\uB09C 12\uC6D4\uAE4C\uC9C0\uC758 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","date":"2026-01-02T00:00:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"2026\uB144 1\uC6D4","description":"Suprema Docs\uB97C \uCC98\uC74C \uBC30\uD3EC\uD55C \uD6C4 \uC9C0\uB09C 12\uC6D4\uAE4C\uC9C0\uC758 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.","slug":"2026-01-02-changelog","isTranslationMissing":false},"unlisted":false,"prevItem":{"title":"2026\uB144 3\uC6D4","permalink":"/docs/changelog/2026-03-changelog"}},"content":"**Suprema Docs**\uB294 \uC288\uD504\uB9AC\uB9C8\uC758 \uBAA8\uB4E0 \uC81C\uD488 \uC124\uBA85\uC11C\uC640 \uAE30\uC220 \uBB38\uC11C\uB97C \uD55C \uACF3\uC5D0 \uBAA8\uC544 \uB193\uC740 \uC9C0\uC2DD \uD5C8\uBE0C\uC785\uB2C8\uB2E4. \uC544\uB798\uC640 \uAC19\uC740 \uC8FC\uC694 \uBB38\uC11C\uB97C \uD3EC\uD568\uD569\uB2C8\uB2E4.\\n\\n* **\uC81C\uD488 \uC124\uBA85\uC11C**: \uC288\uD504\uB9AC\uB9C8 \uC81C\uD488 \uC124\uCE58 \uBC0F \uC0AC\uC6A9 \uC124\uBA85\uC11C\\n\\n* **\uC194\uB8E8\uC158 \uC124\uBA85\uC11C**\\n\\n  * BioStar X \uC0AC\uC6A9 \uC124\uBA85\uC11C\\n\\n  * BioStar Air \uC0AC\uC6A9 \uC124\uBA85\uC11C(\uC608\uC815)\\n\\n* **\uAE30\uC220 \uBB38\uC11C**: API \uBC0F \uAE30\uD0C0 \uAE30\uC220 \uC790\uB8CC\\n\\n* **\uB9B4\uB9AC\uC2A4 \uB178\uD2B8**\\n\\n\uC544\uB798\uB294 2026\uB144 1\uC6D4\uC758 \uC8FC\uC694 \uC5C5\uB370\uC774\uD2B8 \uB0B4\uC5ED\uC785\uB2C8\uB2E4.\\n\\n![Suprema Docs](/img/changelogs-202501.png)\\n\\n{/*truncate*/}\\n\\n## BioStar X\\n\\n* [BioStar X v1.0.1 \uB9B4\uB9AC\uC2A4 \uB178\uD2B8](../platform/biostar_x/release-notes/101) \uBB38\uC11C \uCD94\uAC00\\n\\n* [IR \uD398\uC774\uC2A4](../platform/biostar_x/enroll-credential-ir-face) \uD06C\uB9AC\uB374\uC15C\uC774 \uCD94\uAC00\uB418\uC5B4 \uAD00\uB828 \uAC00\uC774\uB4DC \uCD94\uAC00\\n\\n* [\uB9AC\uBAA8\uD2B8 \uC561\uC138\uC2A4](../platform/biostar_x/settings-remote-access) \uC124\uC815 \uBC0F \uC0AC\uC6A9 \uC548\uB0B4 \uAC00\uC774\uB4DC \uCD94\uAC00\\n\\n* [\uAC00\uC0C1 \uC7A5\uCE58](../platform/biostar_x/settings-virtual-device-event-log) \uAE30\uB2A5\uC73C\uB85C \uC774\uBCA4\uD2B8 \uB85C\uADF8 \uC5F0\uB3D9 \uAC00\uC774\uB4DC \uCD94\uAC00\\n\\n* \uC0AC\uC6A9\uC790 \uBC0F \uB370\uC774\uD130, \uAC10\uC0AC \uCD94\uC801 \uAD00\uB828 \uBA54\uB274\uC5D0\uC11C \uC778\uC1C4 \uB610\uB294 \uB0B4\uBCF4\uB0B4\uAE30 \uC791\uC5C5 \uC2DC \uC0AC\uC720\uB97C \uC785\uB825\uD560 \uC218 \uC788\uB294 \uAE30\uB2A5 \uCD94\uAC00\uC5D0 \uB530\uB978 \uAC00\uC774\uB4DC \uC5C5\uB370\uC774\uD2B8\\n\\n  * [\uC0AC\uC6A9\uC790 \uC815\uBCF4 \uB0B4\uBCF4\uB0B4\uAE30/\uAC00\uC838\uC624\uAE30](../platform/biostar_x/export-import-user-info)\\n\\n  * [\uB9AC\uD3EC\uD2B8 \uC0DD\uC131\uD558\uAE30](../platform/biostar_x/data-generate-reports)\\n\\n  * [\uAC10\uC0AC \uCD94\uC801 \uAD00\uB9AC\uD558\uAE30](../platform/biostar_x/settings-system-audit-trail)\\n\\n* [\uB77C\uC774\uC120\uC2A4 \uC815\uCC45](../platform/biostar_x/licensing) \uC138\uBD80 \uC0AC\uD56D \uC5C5\uB370\uC774\uD2B8\\n\\n  * Base License \uC5C6\uC744 \uB54C \uC7A5\uCE58 \uCD94\uAC00 \uBD88\uAC00 \uC548\uB0B4\\n\\n  * \uC774\uB354\uB137 \uC5F0\uACB0 \uC7A5\uCE58 \uB300\uC218 \uC81C\uD55C \uCD94\uAC00\\n\\n  * \uCD5C\uB300 \uAD00\uB9AC\uC790 \uC218 \uC124\uBA85 \uCD94\uAC00\\n\\n* [BioStar X API](../developer/bsxapi) \uBB38\uC11C \uCD94\uAC00\\n\\n* \uBCF5\uC7A1\uD55C \uB77C\uC774\uC120\uC2A4 \uC694\uAD6C \uC0AC\uD56D\uC744 \uD574\uACB0\uD558\uB294 \uB370 \uB3C4\uC6C0\uC774 \uB418\uB294 [BioStar X \uB77C\uC774\uC120\uC2A4 \uACC4\uC0B0\uAE30](../bsx-license-calculator) \uD398\uC774\uC9C0 \uCD94\uAC00\\n\\n## Devices\\n\\n\uCD5C\uC2E0\uC758 \uC7A5\uCE58 \uB9E4\uB274\uC5BC\uC744 \uBAA8\uB450 \uC5C5\uB370\uC774\uD2B8\uD588\uC2B5\uB2C8\uB2E4. **Suprema Docs**\uC5D0\uC11C \uD655\uC778\uD560 \uC218 \uC788\uB294 \uC7A5\uCE58 \uB9E4\uB274\uC5BC\uC740 \uC544\uB798\uC640 \uAC19\uC2B5\uB2C8\uB2E4.\\n\\n### Biometric Devices\\n\\n* [BioEntry W3](../device/bioentry_w3/)\\n* [BioStation 2a](../device/biostation_2a)\\n* [BioStation 3](../device/biostation_3)\\n* [FaceStation F2](../device/facestation_f2)\\n* [FaceStation 2](../device/facestation_2)\\n* [BioLite N2](../device/biolite_n2)\\n* [BioEntry W2](../device/bioentry_w2)\\n* [BioEntry P2](../device/bioentry_p2)\\n* [BioEntry R2](../device/bioentry_r2)\\n\\n### RF/Mobile Devices\\n\\n* [X-Station 2](../device/xstation_2)\\n* [XPass 2](../device/xpass_2)\\n* [XPass D2](../device/xpass_d2)\\n* [XPass S2](../device/xpass_s2)\\n\\n### Intelligent Controller\\n\\n* [CoreStation 20](../device/corestation_20)\\n* [CoreStation](../device/corestation_40)\\n* [Enclosure](../device/enclosure)\\n\\n### Peripherals\\n\\n* [Door Interface](../device/doorinterface)\\n* [Input Module](../device/inputmodule)\\n* [Output Module](../device/outputmodule)\\n* [Door Module](../device/doormodule)\\n* [Secure Module](../device/securemodule)\\n* [Extended Module](../device/extendedmodule)\\n* [Extended Module-SC](../device/extendedmodule_sc)\\n\\n### APPS\\n\\n* [Device Manager](../device/device_manager)\\n* [CoreStation Setup Manager](../device/corestation_setup_manager)\\n\\n## \uD5A5\uD6C4 \uACC4\uD68D \uBC0F \uAE30\uB300\uD6A8\uACFC\\n\\n**Suprema Docs**\uB294 \uC9C0\uC18D\uC801\uC73C\uB85C \uBC1C\uC804\uD560 \uAC83\uC785\uB2C8\uB2E4. \uACE0\uAC1D\uACFC \uD30C\uD2B8\uB108\uC758 \uC694\uAD6C \uC0AC\uD56D\uC744 \uB354 \uC798 \uCDA9\uC871\uD558\uAE30 \uC704\uD574 \uCF58\uD150\uCE20\uC758 \uC644\uC131\uB3C4\uC640 \uD488\uC9C8\uC744 \uC9C0\uC18D\uC801\uC73C\uB85C \uC5C5\uB370\uC774\uD2B8\uD560 \uC608\uC815\uC785\uB2C8\uB2E4. \uB610\uD55C \uB0B4\uBD80\uC801\uC73C\uB85C\uB294 \uC81C\uD488 \uAC1C\uBC1C, \uAE30\uC220 \uC9C0\uC6D0 \uBC0F \uC601\uC5C5 \uD65C\uB3D9\uC5D0 \uD544\uC694\uD55C \uC815\uD655\uD55C \uC815\uBCF4\uB97C \uC2E0\uC18D\uD558\uAC8C \uACF5\uC720\uD558\uB294 \uB370 \uB3C4\uC6C0\uC774 \uB420 \uAC83\uC73C\uB85C \uAE30\uB300\uD569\uB2C8\uB2E4. \uB610\uD55C \uBE60\uB978 \uC2DC\uC77C \uB0B4\uC5D0 \uB2E4\uAD6D\uC5B4 \uC9C0\uC6D0\uC744 \uD655\uB300\uD560 \uC608\uC815\uC785\uB2C8\uB2E4. \uACE7 \uC77C\uBCF8\uC5B4, \uC2A4\uD398\uC778\uC5B4 \uBB38\uC11C\uAC00 \uACF5\uAC1C\uB420 \uC608\uC815\uC785\uB2C8\uB2E4."}]}}')}}]);